   216	        /// <param name="value">The value to set.</param>
   217	        public async Task SelectOptionAsync(T value)
   218	        {
   219	            _isProcessingValue = true;
   220	            try
   221	            {
   222	                // #1 needs to close before SetValueAndUpdateTextAsync so that whatever the user puts in ValueChanged can run without the popover being in front of it
   223	                // #2 Use "Open" field instead of property to prevent raising multiple OpenChanged events while selecting item.
   224	                _open = false;
   225	
   226	                await SetValueAndUpdateTextAsync(value);
   227	
   228	                // needs to be open to run the rest of the code
   229	                _open = true;
   230	
   231	                if (_items != null)
   232	                    _selectedListItemIndex = Array.IndexOf(_items, value);
   233	
   234	                var optionText = GetItemString(value);
   235	
   236	                if (!_isCleared)
   237	                    await SetTextAndUpdateValueAsync(optionText, false);
   238	
   239	                _debounceTimer?.Dispose();
   240	
   241	                await BeginValidateAsync();
   242	
   243	                if (!_isCleared)
   244	                {
   245	                    await _elementReference.SetText(optionText);
   246	                }
   247	
   248	                Open = false;
   249	                StateHasChanged();
   250	            }
   251	            finally
   252	            {
   253	                _isProcessingValue = false;
   254	            }
   255	        }
