        protected string Classname =>
            new CssBuilder("mud-select")
                .AddClass(Class)
                .Build();

        protected string InputClassname =>
            new CssBuilder("mud-select-input")
                .AddClass("mud-readonly", GetReadOnlyState())
                .AddClass(InputClass)
