    <OutputType>Exe</OutputType>
    <TargetFramework>net10.0</TargetFramework>
    <ImplicitUsings>enable</ImplicitUsings>
    <Nullable>enable</Nullable>
  </PropertyGroup>
  <ItemGroup>
    <ProjectReference Include="/workspace/MudBlazor/src/MudBlazor/MudBlazor.csproj" />
  </ItemGroup>
</Project>
CSHARP
cat > "$TMP/Program.cs" <<'CSHARP'
using Microsoft.AspNetCore.Components;
using MudBlazor;

static void Assert(bool condition, string message)
{
    Console.WriteLine($"{(condition ? "PASS" : "FAIL")}: {message}");
    if (!condition)
    {
        Environment.ExitCode = 1;
    }
}

var autocompleteType = typeof(MudAutocomplete<string>);
var debounceInterval = autocompleteType.GetProperty("DebounceInterval");
var elapsed = autocompleteType.GetProperty("OnDebounceIntervalElapsed");

Assert(debounceInterval is not null, "MudAutocomplete exposes DebounceInterval");
Assert(debounceInterval?.PropertyType == typeof(int), "DebounceInterval remains int");
Assert(elapsed is not null, "MudAutocomplete exposes OnDebounceIntervalElapsed");
Assert(elapsed?.PropertyType == typeof(EventCallback<string>), "OnDebounceIntervalElapsed is EventCallback<string>");
Assert(elapsed?.GetCustomAttributes(typeof(ParameterAttribute), inherit: true).Length == 1, "OnDebounceIntervalElapsed is a Blazor [Parameter]");
Assert(new MudAutocomplete<string>().DebounceInterval == 100, "DebounceInterval default remains 100ms");

var source = File.ReadAllText("/workspace/MudBlazor/src/MudBlazor/Components/Autocomplete/MudAutocomplete.razor.cs");
Assert(source.Contains("await OnDebounceIntervalElapsed.InvokeAsync(ReadText);"), "Elapsed callback is invoked with current text");
Assert(source.Contains("if (DebounceInterval <= 0)\n                await OpenMenuAsync();\n            else"), "Zero/negative debounce still opens immediately without scheduling elapsed timer");

return Environment.ExitCode;
CSHARP

dotnet run --project "$TMP/Repro.csproj" --nologo /p:SkipBunCompile=true
EOF
chmod +x /tmp/mud_autocomplete_debounce_repro.sh
/tmp/mud_autocomplete_debounce_repro.sh

